// Filtrar solo filas que tienen URL de LinkedIn pero NO tienen resumen
const items = $input.all();
const pendientes = [];

for (const item of items) {
  const url = item.json['URL LinkedIn'] || item.json['url_linkedin'] || '';
  const resumen = item.json['Resumen'] || item.json['resumen'] || '';
  const estado = item.json['Estado'] || item.json['estado'] || '';

  // Solo procesar si tiene URL y no tiene resumen aún
  if (url && url.includes('linkedin.com') && !resumen && estado !== 'Completado') {
    pendientes.push({
      json: {
        ...item.json,
        linkedin_url: url.trim(),
        row_number: item.json['row_number'] || item.json['__row_number'] || 0
      }
    });
  }
}

// Tomar solo el primero pendiente (uno a la vez)
if (pendientes.length > 0) {
  return [pendientes[0]];
}

// Si no hay pendientes, no continuar
return [];

// Alternativa gratuita: buscar perfil via Google Search + scraping básico
// Usar cuando no se tiene Proxycurl
const linkedinUrl = $('Filtrar Pendientes (1 a la vez)').first().json.linkedin_url;

// Extraer el username del URL
const username = linkedinUrl.split('/in/')[1]?.replace(/\/$/, '') || 'unknown';
const searchName = username.replace(/-/g, ' ');

return [{
  json: {
    linkedin_url: linkedinUrl,
    search_name: searchName,
    username: username,
    source: 'web_search',
    nota: 'Datos obtenidos por búsqueda web - completar manualmente si falta info'
  }
}];

// Preparar datos del perfil para Claude
const profile = $json;
const originalData = $('Filtrar Pendientes (1 a la vez)').first().json;

// Construir contexto del perfil
let profileContext = '';

if (profile.full_name) {
  profileContext += `Nombre: ${profile.full_name}\n`;
}
if (profile.headline) {
  profileContext += `Titular: ${profile.headline}\n`;
}
if (profile.summary) {
  profileContext += `Resumen propio: ${profile.summary}\n`;
}
if (profile.occupation) {
  profileContext += `Ocupación: ${profile.occupation}\n`;
}
if (profile.industry) {
  profileContext += `Industria: ${profile.industry}\n`;
}
if (profile.country_full_name) {
  profileContext += `País: ${profile.country_full_name}\n`;
}
if (profile.city) {
  profileContext += `Ciudad: ${profile.city}\n`;
}

// Experiencia laboral
if (profile.experiences && profile.experiences.length > 0) {
  profileContext += '\nExperiencia laboral:\n';
  for (const exp of profile.experiences) {
    const from = exp.starts_at ? `${exp.starts_at.month}/${exp.starts_at.year}` : '?';
    const to = exp.ends_at ? `${exp.ends_at.month}/${exp.ends_at.year}` : 'Presente';
    profileContext += `- ${exp.title || 'Sin título'} en ${exp.company || 'Sin empresa'} (${from} - ${to})\n`;
    if (exp.description) {
      profileContext += `  ${exp.description.substring(0, 200)}\n`;
    }
  }
}

// Educación
if (profile.education && profile.education.length > 0) {
  profileContext += '\nEducación:\n';
  for (const edu of profile.education) {
    profileContext += `- ${edu.degree_name || ''} ${edu.field_of_study || ''} en ${edu.school || ''}\n`;
  }
}

// Skills
if (profile.skills && profile.skills.length > 0) {
  profileContext += `\nHabilidades: ${profile.skills.join(', ')}\n`;
}

// Certificaciones
if (profile.certifications && profile.certifications.length > 0) {
  profileContext += '\nCertificaciones:\n';
  for (const cert of profile.certifications) {
    profileContext += `- ${cert.name || ''} (${cert.authority || ''})\n`;
  }
}

return [{
  json: {
    profile_context: profileContext,
    full_name: profile.full_name || originalData.linkedin_url,
    headline: profile.headline || '',
    linkedin_url: originalData.linkedin_url,
    row_number: originalData.row_number,
    raw_profile: profile
  }
}];

// Parsear respuesta de Claude y preparar datos para Google Sheets
const claudeResponse = $json;
const prevData = $('Preparar Contexto para Claude').first().json;

let enrichedData = {};

try {
  // Extraer el texto de la respuesta de Claude
  let responseText = '';
  if (claudeResponse.content && claudeResponse.content[0]) {
    responseText = claudeResponse.content[0].text;
  }

  // Intentar parsear JSON (puede venir con ```json ... ```)
  let jsonStr = responseText;
  const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    jsonStr = jsonMatch[1];
  }

  enrichedData = JSON.parse(jsonStr.trim());
} catch (e) {
  enrichedData = {
    nombre_completo: prevData.full_name || 'Error al parsear',
    cargo_actual: prevData.headline || '',
    empresa_actual: '',
    industria: '',
    rubro: '',
    ubicacion: '',
    anos_experiencia: '',
    resumen_profesional: 'Error al procesar con Claude: ' + e.message,
    habilidades_clave: [],
    nivel_decision: '',
    potencial_contacto: '',
    tema_conversacion_sugerido: ''
  };
}

// Generar ID único
const timestamp = new Date().toISOString().slice(0, 19).replace(/[-:T]/g, '');
const idEnrich = `LI-${timestamp}`;

return [{
  json: {
    id_enriquecimiento: idEnrich,
    nombre_completo: enrichedData.nombre_completo || '',
    cargo_actual: enrichedData.cargo_actual || '',
    empresa_actual: enrichedData.empresa_actual || '',
    industria: enrichedData.industria || '',
    rubro: enrichedData.rubro || '',
    ubicacion: enrichedData.ubicacion || '',
    anos_experiencia: enrichedData.anos_experiencia || '',
    resumen_profesional: enrichedData.resumen_profesional || '',
    habilidades_clave: Array.isArray(enrichedData.habilidades_clave) 
      ? enrichedData.habilidades_clave.join(', ') 
      : (enrichedData.habilidades_clave || ''),
    nivel_decision: enrichedData.nivel_decision || '',
    potencial_contacto: enrichedData.potencial_contacto || '',
    tema_conversacion_sugerido: enrichedData.tema_conversacion_sugerido || '',
    url_linkedin: prevData.linkedin_url || '',
    row_number: prevData.row_number,
    fecha_enriquecimiento: new Date().toISOString().slice(0, 10),
    estado: 'Completado'
  }
}];

// Log de éxito
const data = $json;
console.log(`✅ Perfil enriquecido: ${$('Procesar Respuesta Claude').first().json.nombre_completo}`);
console.log(`   URL: ${$('Procesar Respuesta Claude').first().json.url_linkedin}`);
console.log(`   Estado: Completado`);

return [{
  json: {
    status: 'success',
    message: `Perfil enriquecido exitosamente`,
    nombre: $('Procesar Respuesta Claude').first().json.nombre_completo,
    timestamp: new Date().toISOString()
  }
}];

// Capturar y loguear error
const error = $json;
console.log('❌ Error en enriquecimiento LinkedIn:', JSON.stringify(error, null, 2));

return [{
  json: {
    status: 'error',
    message: error.message || 'Error desconocido',
    timestamp: new Date().toISOString(),
    details: error
  }
}];
